import{_ as a,c as i,o as t,$ as s}from"./chunks/framework.ByJNblvT.js";const u=JSON.parse('{"title":"🙋 FAQ","description":"","frontmatter":{},"headers":[],"relativePath":"en-US/guide/faq.md","filePath":"en-US/guide/faq.md","lastUpdated":1774623019000}'),n={name:"en-US/guide/faq.md"};function l(o,e,r,h,d,c){return t(),i("div",null,[...e[0]||(e[0]=[s(`<h1 id="🙋-faq" tabindex="-1">🙋 FAQ <a class="header-anchor" href="#🙋-faq" aria-label="Permalink to “🙋 FAQ”">​</a></h1><h2 id="after-initializing-the-chart-why-can-i-only-see-a-single-line" tabindex="-1">After initializing the chart, why can I only see a single line? <a class="header-anchor" href="#after-initializing-the-chart-why-can-i-only-see-a-single-line" aria-label="Permalink to “After initializing the chart, why can I only see a single line?”">​</a></h2><p>The chart always fills its container, so first check whether the container has a height.</p><h2 id="the-candlesticks-look-almost-like-a-single-line-and-there-is-no-visible-fluctuation-what-should-i-do" tabindex="-1">The candlesticks look almost like a single line and there is no visible fluctuation. What should I do? <a class="header-anchor" href="#the-candlesticks-look-almost-like-a-single-line-and-there-is-no-visible-fluctuation-what-should-i-do" aria-label="Permalink to “The candlesticks look almost like a single line and there is no visible fluctuation. What should I do?”">​</a></h2><p>You need to set the precision when setting the symbol. Call <code>setSymbol({ ticker: &#39;TestSymbol&#39;, pricePrecision: 6, volumePrecision: 6 })</code>.</p><h2 id="how-do-i-create-a-time-sharing-chart" tabindex="-1">How do I create a time-sharing chart? <a class="header-anchor" href="#how-do-i-create-a-time-sharing-chart" aria-label="Permalink to “How do I create a time-sharing chart?”">​</a></h2><p>Use style settings.</p><div class="language-javascript"><button title="Copy Code" class="copy"></button><span class="lang">javascript</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">chart.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">setStyles</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">({</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  candle: {</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    type: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;area&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  },</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">});</span></span></code></pre></div><h2 id="the-data-calculated-by-a-built-in-technical-indicator-is-not-what-i-want-what-should-i-do" tabindex="-1">The data calculated by a built-in technical indicator is not what I want. What should I do? <a class="header-anchor" href="#the-data-calculated-by-a-built-in-technical-indicator-is-not-what-i-want-what-should-i-do" aria-label="Permalink to “The data calculated by a built-in technical indicator is not what I want. What should I do?”">​</a></h2><p>You can override <code>calc</code> through the chart methods <code>createIndicator</code> or <code>overrideIndicator</code>.</p><h2 id="how-do-i-create-an-indicator-other-than-the-built-in-technical-indicators" tabindex="-1">How do I create an indicator other than the built-in technical indicators? <a class="header-anchor" href="#how-do-i-create-an-indicator-other-than-the-built-in-technical-indicators" aria-label="Permalink to “How do I create an indicator other than the built-in technical indicators?”">​</a></h2><p>The chart supports custom technical indicators. See <a href="/en-US/guide/indicator">Indicators</a> for details.</p><h2 id="how-can-i-mark-buy-and-sell-points" tabindex="-1">How can I mark buy and sell points? <a class="header-anchor" href="#how-can-i-mark-buy-and-sell-points" aria-label="Permalink to “How can I mark buy and sell points?”">​</a></h2><p>You can use overlays. One built-in overlay is <code>simpleAnnotation</code>, which can be created through the chart API: <code>createOverlay({ name: &#39;simpleAnnotation&#39;, ... })</code>.</p><h2 id="why-is-there-no-data-on-the-chart-at-all" tabindex="-1">Why is there no data on the chart at all? <a class="header-anchor" href="#why-is-there-no-data-on-the-chart-at-all" aria-label="Permalink to “Why is there no data on the chart at all?”">​</a></h2><p>Check the following first:</p><ul><li>Whether <code>getBars</code> actually calls <code>callback(data)</code></li><li>Whether <code>setSymbol(...)</code> and <code>setPeriod(...)</code> have been set</li><li>Whether the returned data matches the <code>KLineData[]</code> structure</li><li>Whether <code>timestamp</code> is in milliseconds</li></ul><p>For details, see <a href="/en-US/guide/data-integration">Data integration</a>.</p><h2 id="why-is-real-time-data-not-updating" tabindex="-1">Why is real-time data not updating? <a class="header-anchor" href="#why-is-real-time-data-not-updating" aria-label="Permalink to “Why is real-time data not updating?”">​</a></h2><p>It is usually one of the following reasons:</p><ul><li><code>callback(bar)</code> is not called inside <code>subscribeBar</code></li><li>The pushed data is not a single <code>KLineData</code></li><li>The <code>timestamp</code> of the latest data is smaller than the current last bar</li><li>The previous subscription is not released correctly after switching the symbol or period</li></ul><h2 id="why-do-duplicate-k-lines-appear" tabindex="-1">Why do duplicate K-lines appear? <a class="header-anchor" href="#why-do-duplicate-k-lines-appear" aria-label="Permalink to “Why do duplicate K-lines appear?”">​</a></h2><p>This is usually caused by inconsistent pagination boundary handling, or because the backend returns data with duplicate timestamps. It is recommended to sort and deduplicate the data before passing it into <code>callback(...)</code>.</p><h2 id="why-does-old-data-still-flicker-after-switching-the-symbol-or-period" tabindex="-1">Why does old data still flicker after switching the symbol or period? <a class="header-anchor" href="#why-does-old-data-still-flicker-after-switching-the-symbol-or-period" aria-label="Permalink to “Why does old data still flicker after switching the symbol or period?”">​</a></h2><p>Usually the old real-time subscription was not released correctly in <code>unsubscribeBar</code>. It is recommended to maintain the subscription handle and close it promptly when switching or destroying the chart.</p><h2 id="the-displayed-time-is-incorrect-is-it-a-timezone-issue-or-a-timestamp-issue" tabindex="-1">The displayed time is incorrect. Is it a timezone issue or a timestamp issue? <a class="header-anchor" href="#the-displayed-time-is-incorrect-is-it-a-timezone-issue-or-a-timestamp-issue" aria-label="Permalink to “The displayed time is incorrect. Is it a timezone issue or a timestamp issue?”">​</a></h2><p>Both are common:</p><ul><li>If the overall time is shifted, first check whether <code>setTimezone(...)</code> needs to be set</li><li>If only some data points are abnormal, first check whether timestamps were mistakenly passed in seconds instead of milliseconds</li></ul><h2 id="why-are-indicator-values-incorrect" tabindex="-1">Why are indicator values incorrect? <a class="header-anchor" href="#why-are-indicator-values-incorrect" aria-label="Permalink to “Why are indicator values incorrect?”">​</a></h2><p>Besides the calculation logic itself, also check whether the input data fields are complete.</p><p>For example:</p><ul><li>Most indicators depend on <code>open / high / low / close / volume</code></li><li><code>EMV</code> and <code>AVP</code> also depend on <code>turnover</code></li></ul><h2 id="why-didn-t-my-style-changes-take-effect" tabindex="-1">Why didn&#39;t my style changes take effect? <a class="header-anchor" href="#why-didn-t-my-style-changes-take-effect" aria-label="Permalink to “Why didn&#39;t my style changes take effect?”">​</a></h2><p>It is recommended to check the following in order:</p><ul><li>Whether <code>styles</code> was passed during initialization, or <code>setStyles(...)</code> was called at runtime</li><li>Whether the input is an incremental config, or the nesting level was written incorrectly</li><li>Whether it was overridden again by later code</li></ul><p>For details, see <a href="/en-US/guide/styles">Style configuration</a>.</p>`,36)])])}const m=a(n,[["render",l]]);export{u as __pageData,m as default};
